프로젝트는 스켈레톤 상태입니다. 팔로우 목록 조회 쿼리 최적화를 위한 완전한 예제 코드를 작성하겠습니다. domain 모듈 구조를 기반으로 파일을 생성하겠습니다.

먼저 필요한 디렉토리 구조와 함께 최적화된 Follow Entity 및 Repository를 작성하겠습니다.

**1. Follow Entity 파일 작성**

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt
@Entity
@Table(catalog = "maum", name = "follow", indexes = [
    Index(name = "idx_follower_id", columnList = "follower_id"),
    Index(name = "idx_followee_id", columnList = "followee_id"),
    Index(name = "idx_follower_followee", columnList = "follower_id, followee_id")
])
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val followerId: String,
    val followeeId: String,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", referencedColumnName = "id", insertable = false, updatable = false)
    val follower: UserEntity? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "followee_id", referencedColumnName = "id", insertable = false, updatable = false)
    val followee: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

**2. Repository 인터페이스 - 최적화된 메서드들**

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt
interface FollowRepository : JpaRepository<FollowEntity, String>, QuerydslPredicateExecutor<FollowEntity> {

    // 기본 조회 (N+1 문제 발생)
    fun findByFollowerId(followerId: String): List<FollowEntity>

    // 존재 여부 확인 (최적화)
    fun existsByFollowerIdAndFolloweeId(followerId: String, followeeId: String): Boolean

    // 팔로우 삭제
    fun deleteByFollowerIdAndFolloweeId(followerId: String, followeeId: String): Int
}

// QueryDSL을 활용한 구현체
@Repository
class FollowRepositoryCustomImpl(
    private val queryFactory: JPAQueryFactory
) : FollowRepositoryCustom {

    // 최적화 1: fetch join으로 팔로우 목록 조회 (팔로워 정보 포함)
    override fun findFolloweesByFollowerIdWithFetchJoin(followerId: String): List<FollowEntity> {
        return queryFactory
            .selectFrom(follow)
            .innerJoin(follow.follower, user).fetchJoin()
            .innerJoin(follow.followee, user).fetchJoin()
            .where(follow.followerId.eq(followerId))
            .fetch()
    }

    // 최적화 2: Projection을 활용한 필요한 필드만 조회
    override fun findFolloweesByFollowerIdWithProjection(
        followerId: String,
        pageNo: Int,
        pageSize: Int
    ): Page<FolloweeDTO> {
        val offset = (pageNo - 1L) * pageSize

        val query = queryFactory
            .select(
                Projections.constructor(
                    FolloweeDTO::class.java,
                    follow.followeeId,
                    user.id,
                    user.nickname,
                    user.profileImageUrl,
                    user.status
                )
            )
            .from(follow)
            .innerJoin(user).on(follow.followeeId.eq(user.id))
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())
            .offset(offset)
            .limit(pageSize.toLong())

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetchOne() ?: 0L

        val content = query.fetch()
        return PageImpl(content, PageRequest.of(pageNo - 1, pageSize), total)
    }

    // 최적화 3: 팔로워 목록 조회 (나를 팔로우하는 사람들)
    override fun findFollowersByFolloweeIdWithProjection(
        followeeId: String,
        pageNo: Int,
        pageSize: Int
    ): Page<FollowerDTO> {
        val offset = (pageNo - 1L) * pageSize

        val query = queryFactory
            .select(
                Projections.constructor(
                    FollowerDTO::class.java,
                    follow.followerId,
                    user.id,
                    user.nickname,
                    user.profileImageUrl,
                    user.status
                )
            )
            .from(follow)
            .innerJoin(user).on(follow.followerId.eq(user.id))
            .where(follow.followeeId.eq(followeeId))
            .orderBy(follow.createdAt.desc())
            .offset(offset)
            .limit(pageSize.toLong())

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followeeId.eq(followeeId))
            .fetchOne() ?: 0L

        val content = query.fetch()
        return PageImpl(content, PageRequest.of(pageNo - 1, pageSize), total)
    }

    // 최적화 4: 상호 팔로우 여부 확인 (한 번의 쿼리로)
    override fun isFollowingEachOther(userId1: String, userId2: String): Boolean {
        val count = queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                (follow.followerId.eq(userId1).and(follow.followeeId.eq(userId2)))
                    .or(follow.followerId.eq(userId2).and(follow.followeeId.eq(userId1)))
            )
            .fetchOne() ?: 0L

        return count >= 2L
    }

    // 최적화 5: 배치 조회 - IN 절 활용
    override fun findFolloweesByFollowerIds(
        followerIds: List<String>
    ): Map<String, List<FolloweeDTO>> {
        if (followerIds.isEmpty()) return emptyMap()

        return queryFactory
            .select(
                follow.followerId,
                Projections.constructor(
                    FolloweeDTO::class.java,
                    follow.followeeId,
                    user.id,
                    user.nickname,
                    user.profileImageUrl,
                    user.status
                )
            )
            .from(follow)
            .innerJoin(user).on(follow.followeeId.eq(user.id))
            .where(follow.followerId.`in`(followerIds))
            .fetch()
            .groupBy({ it.get(follow.followerId) as String }, { it.get(1) as FolloweeDTO })
    }
}

