    fun findFolloweesByFollowerIdWithFetchJoin(followerId: String): List<FollowEntity>
    fun findFolloweesByFollowerIdWithProjection(followerId: String, pageNo: Int, pageSize: Int): Page<FolloweeDTO>
    fun findFollowersByFolloweeIdWithProjection(followeeId: String, pageNo: Int, pageSize: Int): Page<FollowerDTO>
    fun isFollowingEachOther(userId1: String, userId2: String): Boolean
    fun findFolloweesByFollowerIds(followerIds: List<String>): Map<String, List<FolloweeDTO>>
}
