**4. Service 레이어 - 캐싱 전략 포함**

```kotlin
// application/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>
) {

    companion object {
        private const val FOLLOW_LIST_CACHE_PREFIX = "follow:list:"
        private const val FOLLOW_LIST_CACHE_TTL_MINUTES = 30L
    }

    // 팔로우 목록 조회 - 캐싱 적용
    fun getFolloweeList(
        followerId: String,
        pageNo: Int = 1,
        pageSize: Int = 20
    ): FollowListResponse {
        val cacheKey = "${FOLLOW_LIST_CACHE_PREFIX}${followerId}:${pageNo}:${pageSize}"

        // 캐시 조회
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) {
            return cached as FollowListResponse
        }

        // 데이터베이스 조회 (최적화된 쿼리)
        val page = followRepository.findFolloweesByFollowerIdWithProjection(
            followerId, pageNo, pageSize
        )

        val response = FollowListResponse(
            totalCount = page.totalElements.toInt(),
            pageNo = pageNo,
            pageSize = pageSize,
            items = page.content
        )

        // 캐시 저장
        redisTemplate.opsForValue().set(
            cacheKey,
            response,
            Duration.ofMinutes(FOLLOW_LIST_CACHE_TTL_MINUTES)
        )

        return response
    }

    // 팔로워 목록 조회 - 캐싱 적용
    fun getFollowerList(
        followeeId: String,
        pageNo: Int = 1,
        pageSize: Int = 20
    ): FollowListResponse {
        val cacheKey = "follow:followers:${followeeId}:${pageNo}:${pageSize}"

        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) {
            return cached as FollowListResponse
        }

        val page = followRepository.findFollowersByFolloweeIdWithProjection(
            followeeId, pageNo, pageSize
        )

        val response = FollowListResponse(
            totalCount = page.totalElements.toInt(),
            pageNo = pageNo,
            pageSize = pageSize,
            items = page.content
        )

        redisTemplate.opsForValue().set(
            cacheKey,
            response,
            Duration.ofMinutes(FOLLOW_LIST_CACHE_TTL_MINUTES)
        )

        return response
    }

    // 팔로우 추가 - 캐시 무효화
    @Transactional
    fun follow(followerId: String, followeeId: String): Boolean {
        val exists = followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)
        if (exists) return false

        val follow = FollowEntity(
            followerId = followerId,
            followeeId = followeeId
        )
        followRepository.save(follow)

        // 캐시 무효화
        invalidateFollowCache(followerId, followeeId)
        return true
    }

    // 팔로우 취소 - 캐시 무효화
    @Transactional
    fun unfollow(followerId: String, followeeId: String): Boolean {
        val deletedCount = followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)

        if (deletedCount > 0) {
            invalidateFollowCache(followerId, followeeId)
            return true
        }
        return false
    }

    private fun invalidateFollowCache(followerId: String, followeeId: String) {
        val pattern1 = "${FOLLOW_LIST_CACHE_PREFIX}${followerId}:*"
        val pattern2 = "follow:followers:${followeeId}:*"

        redisTemplate.keys(pattern1).forEach { key ->
            redisTemplate.delete(key)
        }
        redisTemplate.keys(pattern2).forEach { key ->
            redisTemplate.delete(key)
        }
    }
}
