@Component
class FollowResolver(
    private val followService: FollowService
) {

    @QueryMapping
    fun getFolloweeList(
        @Argument followerId: String,
        @Argument pageNo: Int = 1,
        @Argument pageSize: Int = 20
    ): FollowListResponse {
        return followService.getFolloweeList(followerId, pageNo, pageSize)
    }

    @QueryMapping
    fun getFollowerList(
        @Argument followeeId: String,
        @Argument pageNo: Int = 1,
        @Argument pageSize: Int = 20
    ): FollowListResponse {
        return followService.getFollowerList(followeeId, pageNo, pageSize)
    }

    @MutationMapping
    fun follow(
        @Argument followerId: String,
        @Argument followeeId: String
    ): Boolean {
        return followService.follow(followerId, followeeId)
    }

    @MutationMapping
    fun unfollow(
        @Argument followerId: String,
        @Argument followeeId: String
    ): Boolean {
        return followService.unfollow(followerId, followeeId)
    }
}
